changeSet.sql:
ALTER TABLE communication.comm_delivery ADD COLUMN IF NOT EXISTS template_locale VARCHAR(15), ADD COLUMN IF NOT EXISTS policy_decision VARCHAR(32), ADD COLUMN IF NOT EXISTS policy_reason VARCHAR(200);
UPDATE communication.comm_delivery SET template_locale = COALESCE(template_locale, 'en'), policy_decision = COALESCE(policy_decision, 'ALLOWED'), policy_reason = COALESCE(policy_reason, 'MIGRATED_DEFAULT') WHERE template_locale IS NULL OR policy_decision IS NULL OR policy_reason IS NULL;
CREATE INDEX IF NOT EXISTS idx_comm_delivery_policy_decision ON communication.comm_delivery (policy_decision, created_at DESC);

changeSet.rollback:
DROP INDEX IF EXISTS communication.idx_comm_delivery_policy_decision;
ALTER TABLE communication.comm_delivery
    DROP COLUMN IF EXISTS template_locale,
    DROP COLUMN IF EXISTS policy_decision,
    DROP COLUMN IF EXISTS policy_reason;
